C<pre><code>#include &lt;stdio.h&gt;

int main(void) {
    int secondi;
    printf("Inserire un numero di secondi: ");
    scanf("%d", &amp;secondi);

    if( secondi&lt;0 )
        printf("Valore inserito non corretto.\n");
    else {
        int hh = secondi/3600;
        int mm = (secondi - hh*3600)/60;
        int ss = secondi - hh*3600 - mm*60;
        printf("Orario: %02d:%02d:%02d\n", hh, mm, ss);
    }

    return 0;
}
