C<pre><code>#include &lt;stdio.h&gt;

int main(void) {
    printf("Numeri da 1 a 100\n");
    for(int n=1; n&lt;=100; n++)
        printf("%d ", n);

    printf("\n\nNumeri da 100 a 1\n");
    for(int n=100; n&gt;=1; n--)
        printf("%d ", n);

    printf("\n\nNumeri da 1 a 100 pari\n");
    for(int n=2; n&lt;=100; n+=2)
        printf("%d ", n);

    printf("\n\nNumeri da 100 a 1 dispari\n");
    for(int n=99; n&gt;=1; n-=2)
        printf("%d ", n);

    printf("\n\nLa tabellina del 3 fino a 100\n");
    for(int n=1; n*3&lt;=100; n++)
        printf("%d ", n*3);

    printf("\n\nPotenze del 2 minori di 10000\n");
    for(int n=1; n&lt;=10000; n*=2)
        printf("%d ", n);

    printf("\n\n");
    return 0;
}
</code></pre>

C<pre><code>#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;time.h&gt;

int main(void) {
    srand(time(NULL));
    int n = rand() % 100 + 1;

    int valore=0;
    printf("Indovina il numero! (tra 1 e 100)\n");
    for(int i=1; i&lt;=10 &amp;&amp; valore!=n; i++){
        printf("Tentativo %d: ", i);
        scanf("%d", &amp;valore);

        if(valore == n)
            printf("Complimenti hai indovinato in %d mosse!\n", i);
        else if(valore &gt; n)
            printf("%d è troppo grande... riprova!\n", valore);
        else
            printf("%d è troppo piccolo... riprova!\n", valore);
    }
    return 0;
}
</code></pre>

C<pre><code>#include &lt;stdio.h&gt;

int main(void) {
    int numero;

    printf("Inserire un numero: ");
    scanf("%d", &amp;numero);

    int cifre = 1;
    for(int base=10; numero/base &gt; 0; base*=10)
        cifre++;

    printf("%d è composto da %d cifr%c in base 10\n", numero, cifre, cifre==1 ? 'a':'e');

    cifre = 1;
    for(int base=2; numero/base &gt; 0; base*=2)
        cifre++;

    printf("%d è composto da %d cifr%c in base 2\n", numero, cifre, cifre==1 ? 'a':'e');

    return 0;
}
</code></pre>

C<pre><code>#include &lt;stdio.h&gt;

int main(void) {
    int valore, max, somma=0;
    int inseriti = 0;
    // int uscita;
    char uscita;

    do {
        printf("Inserire un numero: ");
        scanf("%d", &amp;valore);

        if( inseriti == 0 )
            max = valore;
        else if( valore &gt; max )
            max = valore;
        somma += valore;
        inseriti++;

        printf("Vuoi terminare (S o N)? ");
        // Uso \n%c per evitare la lettura dello \n lasciato dalla precedente scanf
        scanf("\n%c", &amp;uscita);
