#include &lt;math.h&gt;

void stampa(int valori[], int len){
    for(int i=0; i&lt;len; i++)
        printf("%d ", valori[i]);
}

int minimo(int valori[], int len){
    int min = valori[0];
    for(int i=1; i&lt;len; i++)
        if(valori[i] &lt; min)
            min = valori[i];
    return min;
}

int massimo(int valori[], int len){
    int max = valori[0];
    for(int i=1; i&lt;len; i++)
        if(valori[i] &gt; max)
            max = valori[i];
    return max;
}

float media(int valori[], int len){
    float somma = 0;
    for(int i=0; i&lt;len; i++)
        somma += valori[i];
    return somma / len;
}

int moda(int valori[], int len){
    int index, frequenza = 0;
    for(int i=0; i&lt;len; i++){
        int freq = 1;
        for(int j=i+1; j&lt;len; j++)
            if( valori[i] == valori[j] )
                freq++;
        if(freq &gt; frequenza){
            frequenza = freq;
            index = i;
        }
    }
    if( frequenza == 1 )
        return -1;
    return index;
}

int mediana(int valori[], int len){
    return valori[len/2];
}

float varianza(int valori[], int len){
    float avg = media(valori, len);
    float somma;
    for(int i=0; i&lt;len; i++)
        somma += pow(valori[i] - avg, 2);
    return somma / len;
}

