    for(int i=0; i&lt;DIM; i++){
        numeri[i] = rand() % 1000;
        printf("%d ", numeri[i]);
    }

    /*********** BUBBLE SORT ***********/
    for(int i=DIM-1; i&gt;0; i--)
        for(int j=0; j&lt;i; j++)
            if(numeri[j] &gt; numeri[j+1]){
                int tmp = numeri[j];
                numeri[j] = numeri[j+1];
                numeri[j+1] = tmp;
            }
    /***********************************/

