#define DIM 100

void scambia(int vett[], int a, int b){
    int tmp = vett[a];
    vett[a] = vett[b];
    vett[b] = tmp;
}

int partition(int vett[], int sx, int dx){
    int i=sx-1, j=dx;
    int val = vett[dx];

    for(;;){
        while(vett[++i] &lt; val);
        while(val &lt; vett[--j])
            if( j==sx )
                break;
        if( i&gt;=j )
            break;
        scambia(vett, i, j);
    }
    scambia(vett, i, dx);

    return i;
}

void quickSort(int vett[], int sx, int dx){ 
    if (sx &lt; dx) { 
        /* Partizionamento dell'array */
        int pivot = partition(vett, sx, dx); 
        quickSort(vett, sx, pivot - 1); 
        quickSort(vett, pivot + 1, dx); 
    } 
} 

int main(void) {
    srand(time(NULL));

