        for(int i=altezza; piena &amp;&amp; i&gt;0; i--)
            torre.add(new Disco(i, altezza));
    }

    public Disco estraiDisco() {
        if(torre.size()==0)
            return null;
        return torre.remove(torre.size()-1);
    }

    public boolean inserisciDisco(Disco d) {
        if( d==null || torre.size()&gt;0 &amp;&amp; d.compareTo(torre.get(torre.size()-1)) &gt; 0 )
            return false;
        torre.add(d);
        return true;
    }

    @Override
    public String toString() {
        String risultato = "";
        for(int i=altezza; i&gt;torre.size(); i--)
            risultato += new Disco(0, altezza) + "\n";

        for(int i=torre.size()-1; i&gt;=0; i--)
            risultato += torre.get(i) + "\n";

        for(int i=0; i&lt;(altezza*2-1); i++)
            risultato += "=";
        return risultato;
    }
}
</code></pre> Java<pre><code>public class Disco implements Comparable&lt;Disco&gt; {
    private int dimensione;
    private int tot_dischi;

    public Disco(int dim, int tot_dischi) {
        this.dimensione = dim;
        this.tot_dischi = tot_dischi;
    }

    @Override
    public int compareTo(Disco altro) {
        return dimensione - altro.dimensione;
    }

    @Override
    public String toString() {
        String s = dimensione &gt; 0 ? repeat("#", dimensione*2-1) : "|";
        int n_spazi = tot_dischi - dimensione;
        if( dimensione == 0 )
            n_spazi -= 1;
        return repeat(" ", n_spazi) + s + repeat(" ", n_spazi);
    }

    private static String repeat(String s, int times) {
        String result = "";
        for(int i=0; i&lt;times; i++)
            result += s;
        return result;
    }
}
