public class Portamonete {
    private int m50cent;
    private int m1euro;
    private int m2euro;

    public Portamonete() {
        m50cent = 0;
        m1euro = 0;
        m2euro = 0;
    }

    public Portamonete(int m50cent, int m1euro, int m2euro) {
        this.m50cent = m50cent;
        this.m1euro = m1euro;
        this.m2euro = m2euro;
    }

    public void inserisci(double valore) {
        if (valore == 0.5)
            m50cent++;
        if (valore == 1)
            m1euro++;
        if (valore == 2)
            m2euro++;
    }

    public void inserisci(double valore, int n) {
        if (n &lt;= 0)
            return;
        if (valore == 0.5)
            m50cent += n;
        if (valore == 1)
            m1euro += n;
        if (valore == 2)
            m2euro += n;
    }

    public double denaro() {
        return 0.5 * m50cent + m1euro + 2 * m2euro;
    }

