                    continue;

                String sostanza = campi[6].trim();
                String regione  = campi[2].trim();
                String asl      = campi[4].trim();
                int    utenti   = Integer.parseInt(utentiStr);

                lista.add(new RecordSerd(sostanza, utenti, regione, asl));
